query:
mutation GenerateDoc($docGenerateInputId: ID!, $fileId: ID, $options: GenerateDocOptions!) {
  generateDoc(
    docGenerateInputId: $docGenerateInputId
    fileId: $fileId
    options: $options
  ) {
    id
    docGenerateInput {
      ...DocGenerateInputFragment
      __typename
    }
    __typename
  }
}

fragment DocGenerateInputFragment on DocGenerateInput {
  id
  docGenerationId
  interactionId
  status
  prompt
  content
  format
  settings
  docId
  docGenerateOutputId
  createdTime
  updatedTime
  __typename
}
